import React, { useState, useEffect } from 'react';
import { Container, Row, Col, Card, Button, Spinner, Form } from 'react-bootstrap';
import { Shop, ArrowRight } from 'react-bootstrap-icons';
import { useNavigate } from 'react-router-dom';
import { publicApi } from '../../services/api';

function BusinessList() {
  const navigate = useNavigate();
  const [businesses, setBusinesses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');

  useEffect(() => {
    loadBusinesses();
  }, []);

  const loadBusinesses = async () => {
    try {
      const data = await publicApi.getBusinesses();
      setBusinesses(data);
    } catch (err) {
      setError('Error al cargar negocios');
    } finally {
      setLoading(false);
    }
  };

  const filteredBusinesses = businesses.filter(b => 
    b.nombre.toLowerCase().includes(search.toLowerCase()) ||
    (b.descripcion && b.descripcion.toLowerCase().includes(search.toLowerCase()))
  );

  if (loading) {
    return (
      <Container className="py-5 text-center">
        <Spinner animation="border" />
      </Container>
    );
  }

  return (
    <Container className="py-5">
      <div className="text-center mb-5">
        <h1 className="display-4 fw-bold mb-3">AppCitas</h1>
        <p className="lead text-muted">Reserva tu cita en los mejores negocios</p>
      </div>

      <Row className="justify-content-center mb-4">
        <Col md={6}>
          <Form.Control
            type="text"
            placeholder="Buscar negocio..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="form-control-lg"
          />
        </Col>
      </Row>

      {error && (
        <div className="alert alert-danger text-center">{error}</div>
      )}

      <Row>
        {filteredBusinesses.map((business) => (
          <Col key={business.id} md={6} lg={4} className="mb-4">
            <Card className="h-100 hover-shadow cursor-pointer" onClick={() => navigate(`/${business.slug}`)}>
              <Card.Body className="p-4">
                <div className="d-flex align-items-center mb-3">
                  {business.logo_url ? (
                    <img
                      src={business.logo_url}
                      alt={business.nombre}
                      className="rounded-circle me-3"
                      style={{
                        width: 60,
                        height: 60,
                        objectFit: 'cover',
                        border: '2px solid ' + (business.color_primario || '#3B82F6'),
                      }}
                      onError={(e) => {
                        // Fallback to icon if image fails to load
                        e.target.style.display = 'none';
                        e.target.nextSibling.style.display = 'flex';
                      }}
                    />
                  ) : <div
                    className="rounded-circle d-flex align-items-center justify-content-center me-3"
                    style={{
                      width: 60,
                      height: 60,
                      backgroundColor: business.color_primario || '#3B82F6',
                      display: business.logo_url ? 'none' : 'flex',
                    }}
                  >
                    <Shop color="white" size={28} />
                  </div>}

                  <div>
                    <h5 className="mb-1 fw-bold">{business.nombre}</h5>
                    <small className="text-muted">{business.direccion}</small>
                  </div>
                </div>
                <p className="text-muted text-truncate-2">{business.descripcion || 'Sin descripción'}</p>
                <Button variant="outline-primary" className="w-100 mt-2">
                  Ver servicios <ArrowRight className="ms-2" />
                </Button>
              </Card.Body>
            </Card>
          </Col>
        ))}
      </Row>
    </Container>
  );
}

export default BusinessList;
